<script setup>
  import { ref, onMounted, nextTick } from 'vue'
  import DeviceBlock from '../components/DeviceBlock.vue'
  import mqtt from 'mqtt/dist/mqtt'
  // import server_cert from '../assets/server.crt'
  const alert = ref({
    show: false,
    message: "",
    style: "alert-success"
  })

  const pub_options = {qos: 1, retain: true};

  const clientId = `mqtt_${Math.random().toString(16).slice(3)}`
  var connection = {
    host: 'bad-day.today',
    port: 8091,
    endpoint: '/',
    clean: true, // Reserved session
    connectTimeout: 4000, //  overtime time
    reconnectPeriod: 4000, //  Rest continuous interval
    //  Certification Information
    clientId: clientId,
    username: 'web',
    password: 'webui',
    rejectUnauthorized: false,
  }

  const itemRefs = ref([])
  var client = {
    connected: false,
  }

  onMounted(() => {
    const { host, port, endpoint, ...options } = connection
    const connectUrl = `ws://${host}:${port}${endpoint}`
    try {
      client = mqtt.connect(connectUrl, options)
      client.on('connect', () => {
        setAlert("alert-success", "Connected to MQTT server!")
        console.log('Connection succeeded!')
        let to_sub = []
        to_sub.push("+/status/connection")
        groceryList.value.forEach(element => subscribeElement(to_sub, element));
        client.subscribe(to_sub, () => {
          console.log(`Subscribed to topics`)
        })
      })
      client.on("reconnect", () => {
        setAlert("alert-warning", "Reconnecting to MQTT server!")
      });
      client.on('error', error => {
        console.log('Connection failed', error)
        setAlert("alert-danger", "MQTT Error: " + error)
      })
      client.on('message', (topic, message) => {
        // console.log(`Received: ${topic} -> ${message}`)
        // itemRefs.value.forEach(checkMessageFor, {message, topic});
        let allFalse = itemRefs.value.every(checkMessageFor, { message, topic });
        if (allFalse && topic.split('/')[1] == "status" && topic.split('/')[2] == "connection") {
          console.log("Adding new device " + topic.split('/')[0])
          let newElement = {id: groceryList.value.length, text: topic.split('/')[0], conn: "Disconnected"}
          groceryList.value.push(newElement)
          let new_sub_array = []
          subscribeElement(new_sub_array, newElement)
          client.subscribe(new_sub_array, () => {
            console.log(`Subscribed to new topics`)
          })
          // DOM updated
          nextTick(function () {
            itemRefs.value.forEach(checkMessageFor, {message, topic})
          });
        }
      })
      client.on("close", () => {
        setAlert("alert-danger", "Connection lost to MQTT server!")
      })
    } catch (error) {
      console.log('mqtt.connect error', error)
    }
  })

  function subscribeElement(to_sub, element) {
    to_sub.push(element.text + "/status/ota/status")
    to_sub.push(element.text + "/status/debug/startup")
    to_sub.push(element.text + "/status/debug/messages")
    to_sub.push(element.text + "/status/debug/enabled")
  }

  function checkMessageFor(element) {
    if (this.topic.split('/')[0] == element.device.name.text) {
      element.onMessage(this.message, this.topic)
      return false
    }
    return true
  }
  
  function setAlert(style, message) {
    // console.log(style)
    alert.value.style = style
    alert.value.message = message
    alert.value.show = true
    setTimeout(() => { alert.value.show = false }, 1500);
  }

  function debugChanged(name, state) {
    console.log(name + " -> " + state)
    // client.publish(name + "/set/debug/enabled", state)
    client.publish(name + "/set/debug/enabled", new Uint8Array([state ? 1 : 0]), pub_options, error => {
    if (error) {
      console.log('Publish error', error)
    }
  })
  }

  const groceryList = ref([
    { id: 0, text: 'PowerMeter-45BD9E7C', conn: "Disconnected" },
    // { id: 1, text: 'PowerMeter-F4BD9E7C', conn: "Disconnected" },
    // { id: 2, text: 'ESPCamera-FCAB6224', conn: "Disconnected" },
  ])

</script>

<template>
  <Transition name="fade">
    <div v-show="alert.show" :class="['alert ', alert.style]" role="alert">{{alert.message}}</div>
  </Transition>
  <div class="row mt-4">
    <DeviceBlock
        v-for="item in groceryList"
        @debug-change="debugChanged"
        :name="item"
        :conn="item.conn"
        :key="item.id"
        ref="itemRefs"
        ></DeviceBlock>
  </div>        
</template>
    
<style scoped>
.fade-enter-active,
.fade-leave-active {
  transition: opacity 0.3s ease-out;
}

.fade-enter-from,
.fade-leave-to {
  opacity: 0;
}
</style>