<script setup>
    // import { ref, watchEffect } from 'vue'
    import { ref, onMounted } from 'vue'
    // import ArrowDown from '../../public/arrow-down.svg';

    const emit = defineEmits(['debugChange'])

    const device = defineProps({
        name: Object
    })
    const API_URL = "http://bad-day.today:3000/ota/upload"
    const spin_active = ref(false)
    const send_btn_val = ref("Upload")
    const device_status = ref("Idle")
    const device_conn = ref("Disconnected")
    const device_conn_style = {
        color: "red"
    }
    const device_conn_state = ref(false)

    const show_debug = ref(true)
    const debug_messages = ref([])

    onMounted(() => {
    })

    function onMessage(data, topic) {
        let topic_parts = topic.split('/')

        if (topic_parts[1] == "status") {
            switch (topic_parts[2]) {
                case "connection": {
                    console.log(`Received: ${topic} -> ${data}`)
                    let parsed = JSON.parse(data)
                    setConn(parsed.conn == "true", parsed.version.split("_")[0]);
                    // console.log(this.message.toString())
                } break;
                case "ota": {
                    if (topic_parts[3] != "status") {
                        break;
                    }
                    device_status.value = "Updating: " + data + "%"
                    if (data == 100) {
                        device_status.value = "Update Finished"
                        spin_active.value = false
                        send_btn_val.value = "Upload"
                    } else {
                        spin_active.value = true
                        send_btn_val.value = "In Progress..."
                    }
                } break;
                case "debug": {
                    let first_lvl = topic_parts[3]
                    if(first_lvl == "startup") {
                        let parsed = JSON.parse(data)
                        debug_messages.value = []
                        console.log("Startup messages:")
                        parsed.messages.forEach((msg, index) => {
                            console.log(msg)
                            debug_messages.value.unshift({id: index+1, text: msg, time: new Date().toTimeString().split(" ")[0]})
                        });
                    } else if (first_lvl == "messages") {
                        let msg = data.toString();
                        debug_messages.value.unshift({id: msg.split(":")[0], text: msg.replace(msg.split(":")[0] + ":", ""), time: new Date().toTimeString().split(" ")[0]})
                    } else if (first_lvl == "enabled") {
                        console.log("Got debug enabled: " + data)
                        data == 0 ? show_debug.value = false : show_debug.value = true
                    }
                } break;
            }
        } else if (topic_parts[1] == "set") {
        // Empty for now
        }
    }

    async function onSubmit(e) {
        e.preventDefault();
        const form = e.currentTarget;
        console.log("Submitting");
        spin_active.value = true
        send_btn_val.value = "Sending..."

        try {
            const formData = new FormData(form);
            let response = await fetch(API_URL, {
                method: 'POST',
                body: formData
            })
            if (response.status == 200) {
                // spin_active.value = false
                send_btn_val.value = "Sent"
            }
            response = await response.text()

            console.log(response);
        } catch (error) {
            console.error(error);
        }
    }

    function setConn(state, version) {
        device_conn_state.value = state
        device_conn.value = ((state ? "C" : "Disc") + "onnected") + " " + version
        device_conn_style.color = state ? "green" : "red"
    }

    function changeDebug() {
        // show_debug.value = !show_debug.value
        emit('debugChange', device.name.text, !show_debug.value)
    }

    defineExpose({
        onMessage,
        setConn,
        device
    })
</script>

<style scoped>
.header {
  text-align: center;
  padding: 1rem 0;
  position: fixed;
  width: 100%;
  z-index: 1;
  background-color: rgba(0, 0, 0, 0.9);
}
.header__title {
  color: goldenrod;
}
.header__nav {
  display: flex;
  justify-content: space-evenly;
}
.header__nav__link {
  text-decoration: none;
  color: white;
}
</style>

<template>
    <div class="col-md-6 mb-4">
      <div class="card bg-dark text-white">
        <div class="card-body">
            <div class="row">
                <div class="col-4">
                    <RouterLink class="header__nav__link" :to="'/Dashborad/'+device.name.text">{{device.name.text}}</RouterLink>
                    <!-- <h5 class="card-title">{{device.name.text}}</h5> -->
                </div>
                <div class="col-4 ms-auto text-center">
                    <p class="rounded-pill fs-6" :style="{backgroundColor: device_conn_style.color}">{{device_conn}}</p>
                </div>
            </div>
            <p class="card-text">Device state: {{device_status}}</p>
            <form @submit="onSubmit" id="ota_form" method="post" enctype="multipart/form-data">
                <div class="form-group">
                    <input type="hidden" id="dname" name="device_id" :value=device.name.text />
                    <input class="form-control" type="file" name="firmware">
                    <div class="row">
                        <div class="col-4">
                            <button type="submit" class="btn btn-primary" :disabled="spin_active">
                                <span v-if="spin_active" class="spinner-border spinner-border-sm" role="status" aria-hidden="true"></span>
                                {{send_btn_val}}
                            </button>
                        </div>
                        <div class="col-1 ms-auto">
                            <button class="btn" @click="changeDebug()" type="button">
                                <svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" fill="currentColor" class="bi bi-arrow-down-short" viewBox="0 0 16 16">
                                    <path fill-rule="evenodd" d="M8 4a.5.5 0 0 1 .5.5v5.793l2.146-2.147a.5.5 0 0 1 .708.708l-3 3a.5.5 0 0 1-.708 0l-3-3a.5.5 0 1 1 .708-.708L7.5 10.293V4.5A.5.5 0 0 1 8 4z"/>
                                </svg>
                            </button>
                        </div>
                    </div>
                    <!-- <ArrowDown /> -->
                </div>  
            </form>
            <div v-if="show_debug && device_conn_state" class="row table-responsive" style="max-height: 200px;" id="debug-table">
                <table class="table table-sm" style="color:white">
                    <thead class="thead-dark">
                        <tr>
                        <th scope="col">#</th>
                        <th scope="col">Time</th>
                        <th scope="col">Message</th>
                        </tr>
                    </thead>
                    <tbody>
                        <template v-for="msg in debug_messages" :key="msg.id">
                            <tr><th scope="row">{{msg.id}}</th><td>{{msg.time}}</td><td>{{msg.text}}</td></tr>
                        </template>
                        <!-- <tr><th scope="row">1<td>some time</td><td>message</td></th></tr> -->
                    </tbody>
                </table>
            </div>
        </div>
      </div>
    </div>
</template>