<script setup>
  import { ref, onMounted } from 'vue'
  import mqtt from 'mqtt/dist/mqtt'
  // import Chart from '../components/ChartNr1.ts';
  import Chart from '../components/ChartTst';
  import { useRoute } from 'vue-router'
  // import server_cert from '../assets/server.crt'

  const alert = ref({
    show: false,
    message: "",
    style: "alert-success"
  })

  const id = ref(useRoute().params.id)
//   const pub_options = {qos: 1, retain: true};

  const device = ref({
    connection: {
      text: "N/A",
      style_color: "red",
    }
  })

  const clientId = `mqtt_${Math.random().toString(16).slice(3)}`
  var connection = {
    host: 'bad-day.today',
    port: 8091,
    endpoint: '/',
    clean: true, // Reserved session
    connectTimeout: 4000, //  overtime time
    reconnectPeriod: 4000, //  Rest continuous interval
    clientId: clientId,
    username: 'web',
    password: 'webui',
    rejectUnauthorized: false,
  }

//   const itemRefs = ref([])
  var client = {
    connected: false,
  }

  onMounted(() => {
    const { host, port, endpoint, ...options } = connection
    const connectUrl = `ws://${host}:${port}${endpoint}`
    try {
      client = mqtt.connect(connectUrl, options)
      client.on('connect', () => {
        setAlert("alert-success", "Connected to MQTT server!")
        console.log('Connection succeeded!')
        let to_sub = []
        to_sub.push(id.value + "/status/connection")
        to_sub.push(id.value + "/status/data/main")
        client.subscribe(to_sub, () => {
          console.log(`Subscribed to topics`)
        })
      })
      client.on("reconnect", () => {
        setAlert("alert-warning", "Reconnecting to MQTT server!")
      });
      client.on('error', error => {
        console.log('Connection failed', error)
        setAlert("alert-danger", "MQTT Error: " + error)
      })
      client.on('message', (topic, message) => {
        // console.log(`Received: ${topic} -> ${message}`)
        onMessage(topic, message)
      })
      client.on("close", () => {
        setAlert("alert-danger", "Connection lost to MQTT server!")
      })
    } catch (error) {
      console.log('mqtt.connect error', error)
    }
  })
  
  function setAlert(style, message) {
    // console.log(style)
    alert.value.style = style
    alert.value.message = message
    alert.value.show = true
    setTimeout(() => { alert.value.show = false }, 1500);
  }

var frame_data = ref([
  ['Date', 'SolarPower'],
//   ['0', 0, 0],
]);

const frame = ref({
  solarW: 0,
  solarV: 0,
  acOutW: 0,
  acOutPercent: 0,
  battV: 0,
  battChargeA: 0,
  battDischargeA: 0,
  mode: "N/A",
  rssi: 0,
  tempEnv: 0,
  tempBat: 0,
  date: "N/A"
})

function data_frame(data) {
  let data_parts = data.split(" ")
  this.solarW = data_parts[0]
  this.solarV = data_parts[1]
  this.acOutW = data_parts[2]
  this.acOutPercent = data_parts[3]
  this.battV = data_parts[4]
  this.battChargeA = data_parts[5]
  this.battDischargeA = data_parts[6]
  this.mode = modeToString(data_parts[7])
  this.rssi = data_parts[8]
  this.tempEnv = data_parts[9]
  this.tempBat = data_parts[10]
}

function onMessage(topic, data) {
    // console.log(id.value)
    if (topic.split('/')[0] != id.value) {
        return;
    }

    // let topic_parts = topic.split('/')

    let topic_parts = topic.split('/')
    if (topic_parts[1] == "status") {
      switch (topic_parts[2]) {
        case "connection": {
          // console.log(`Received: ${topic} -> ${data}`)
          let parsed = JSON.parse(data)
          setConn(parsed.conn == "true", parsed.version.split("_")[0]);
          // console.log(this.message.toString())
        } break;
        case "data": {
          let tmp_frame = new data_frame(String(data));
          frame.value = tmp_frame
          frame.value.date = getDate()
          // frame_data.value.push([new Date().toString().split(" ")[4], Number(frame.tempEnv), Number(frame.tempBat)]);
        } break;
      }
    }
}

function setConn(state, version) {
  device.value.connection.text = ((state ? "C" : "Disc") + "onnected") + " " + version
  device.value.connection.style_color = state ? "green" : "red"
}

function getDate() {
  let date_time = new Date();
  let date = ("0" + date_time.getDate()).slice(-2);
  let month = ("0" + (date_time.getMonth() + 1)).slice(-2);
  let year = date_time.getFullYear();
  let hours = ("0" + date_time.getHours()).slice(-2);
  let minutes = ("0" + date_time.getMinutes()).slice(-2);
  let seconds = ("0" + date_time.getSeconds()).slice(-2);
  // prints date & time in YYYY-MM-DD HH:MM:SS format
  return (year + "-" + month + "-" + date + " " + hours + ":" + minutes + ":" + seconds);
}

function modeToString(mode) {
  switch (mode) {
    case 'P':
      return "Power On";
    case 'S':
      return "Standby";
    case 'Y':
      return "Bypass";
    case 'L':
      return "Line";
    case 'B':
      return "Battery";
    case 'T':
      return "Battery Test";
    case 'F':
      return "Fault";
    case 'D':
      return "Shutdown";
    case 'G':
      return "Grid";
    case 'C':
      return "Charge";
    default:
      return "Undefined";
    }
}

</script>
    
<template>
    <Transition name="fade">
        <div v-show="alert.show" :class="['alert ', alert.style]" role="alert">{{alert.message}}</div>
    </Transition>
    <div class="container">
      <div class="row">
        <div class="col-12 ms-auto">
          <h1 :style="{color: device.connection.style_color}">Device Status: {{device.connection.text}}</h1>
        </div>
      </div>
      <div class="row">
        <div class="col-4">
          <h2>Date: {{frame.date}}</h2>
          <h2 :style="{color: frame.mode == 'Line' ? 'red' : 'green'}">Mode: {{frame.mode}}</h2>
        </div>
        <div class="col-4">
          <h2>Solar Power: {{frame.solarW}}W</h2>
          <h2>Solar Voltage: {{frame.solarV}}V</h2>
          <h2>AC Out Power: {{frame.acOutW}}W</h2>
        </div>
        <div class="col-4">
          <h2>Battery Voltage: {{frame.battV}}V</h2>
          <h2>Battery Charge: {{frame.battChargeA}}A</h2>
          <h2>Battery Discharge: {{frame.battDischargeA}}A</h2>
        </div>
      </div>
      <div class="row">
        <div class="col-6">
          <h2>Enviroment Temperature: {{frame.tempEnv}}&#8451;</h2>
        </div>
        <div class="col-6">
          <h2>Battery Temperature: {{frame.tempBat}}&#8451;</h2>
        </div>
      </div>
      <div class="row">
        <div class="col-12">
          <div class="chart-container">
            <Chart />
          </div>
        </div>
      </div>
    </div>
    
</template>

<style scoped>
.content {
    padding: 7rem 2rem;
}
.content__heading {
    text-align: center;
    margin-bottom: 1rem;
}
.content__separator {
    border-color: gray;
    margin-bottom: 1rem;
}
.fade-enter-active,
.fade-leave-active {
  transition: opacity 0.3s ease-out;
}

.fade-enter-from,
.fade-leave-to {
  opacity: 0;
}
.chart-container {
  width: 50%;
  height: 50%;
  margin: auto;
}
</style>