<script setup>
  import { ref, onMounted } from 'vue'
  
// import AppHeader from "./components/AppHeader";
/* 
export default {
  name: 'App',
  components: {
    // AppHeader
  }
} */
  const download_spin_active = ref(false)
  async function downloadFile() {
    download_spin_active.value = true;

    try {
      let response = await fetch('http://bad-day.today:3000/file/app/latest');
      if (response.status === 200) {
        let json_data = await response.json()
        console.log(json_data)
        let response_file = await fetch(json_data.link);
        const data = await response_file.blob();
        const link = document.createElement('a');
        link.href = window.URL.createObjectURL(data);
        link.setAttribute('download', 'test1.apk');
        document.body.appendChild(link);
        link.click();
        link.remove();
      }
    } catch (error) {
      console.error(error);
    }
    
    download_spin_active.value = false;
  }
</script>

<template>
  <nav class="navbar navbar-expand-lg navbar-light bg-light">
    <div class="container-fluid">
      <button class="navbar-toggler" type="button" data-bs-toggle="collapse" data-bs-target="#navbarNav" aria-controls="navbarNav" aria-expanded="false" aria-label="Toggle navigation">
        <span class="navbar-toggler-icon"></span>
      </button>
      <div class="collapse navbar-collapse" id="navbarNav">
        <ul class="navbar-nav">
          <li class="nav-item">
            <router-link class="nav-link active" aria-current="page" to="/">Home</router-link>
          </li>
          <li class="nav-item">
            <router-link class="nav-link" to="/Map">Tracker Map</router-link>
          </li>
          <li class="nav-item">
            <router-link class="nav-link" to="/Graphs">Grafana</router-link>
          </li>
        </ul>
      </div>
      <button @click="downloadFile" class="btn btn-secondary pull-right" :disabled="download_spin_active">
        <span v-if="download_spin_active" class="spinner-border spinner-border-sm" role="status" aria-hidden="true"></span>
          Download App
      </button>
    </div>
  </nav>
  <RouterView />
</template>


