<template>
    <Line v-if="loaded" :chart-data="chartData" />
</template>

<script setup>
    import { ref, onMounted } from 'vue'
    import { Line } from 'vue-chartjs'
    import {
        Chart as ChartJS,
        Title,
        Tooltip,
        Legend,
        BarElement,
        CategoryScale,
        LinearScale,
        LineElement,
        PointElement,
    } from "chart.js";

    ChartJS.register(
        Title,
        Tooltip,
        Legend,
        PointElement,
        BarElement,
        CategoryScale,
        LinearScale,
        LineElement,
    );

    const URL = "http://bad-day.today:3000"

    const name = ref('BarChart')
    const loaded = ref(false)
    var chartData = ref({
        labels: [],
        datasets: [
            {
                label: 'Solar Power',
                // backgroundColor: '#f87979',
                data: [],
                lineTension: 0.75,
                fill: false,
                borderColor: [
                'rgba(200, 99, 132, 1)',
                ],
                // borderWidth: 1,
                backgroundColor: [
                    'rgba(105, 0, 132, .2)',
                ],
                pointBorderColor: 'red',
                pointRadius: 1.5
            },
            {
                label: 'Solar Voltage',
                data: [],
                lineTension: 0.75,
                fill: false,
                hidden: true,
                borderColor: [
                'rgba(0, 0, 132, 1)',
                ],
                // borderWidth: 1,
                // backgroundColor: [
                //     'rgba(105, 0, 132, .2)',
                // ],
                pointBorderColor: 'blue',
                pointRadius: 1.5
            },
        ],
        options: {
            responsive: true,
        },
    })

    onMounted(() => {
        loaded.value = false

        fetchDays().then((days) => {
            if (days) {
                fetchDayFrames(days[0]._id).then((frames) => {
                    if (frames) {
                        // let frame_data = []
                        console.log(frames.length)
                        frames.forEach(frame => {
                            chartData.value.labels.push(new Date(frame.uploadDate).toString().split(" ")[4])
                            chartData.value.datasets[0].data.push(Number(frame.solarW))
                            chartData.value.datasets[1].data.push(Number(frame.solarV))
                            // chartData.value.push([new Date(frame.uploadDate).toString().split(" ")[4], Number(frame.solarW)]);
                        });
                        // chartData.value = frame_data
                        loaded.value = true
                        console.log("Loaded!")
                    }
                })
            }
        })
    })

    async function fetchDays() {
        let data
        try {
            let response = await fetch(URL + "/frame/days")
            if (response.status === 200) {
            data = await response.json();
            // if (data)
            //   console.log(data[0])
            }
        } catch (error) {
            console.error(error);
        }
        return data
        }

    async function fetchDayFrames(date) {
        let data
        try {
            let response = await fetch(URL + "/frame/day/" + date)
            if (response.status === 200) {
            data = await response.json();
            // if (data)
            //   console.log(data[0])
            }
        } catch (error) {
            console.error(error);
        }
        return data
    }
</script>
  